export const legacyLintCatalogs = Object.freeze({
  enUS: Object.freeze(EN_MESSAGES),
  ...Object.fromEntries(LEGACY_LINT_LOCALES.filter((locale) => locale !== "enUS").map((locale) => [
    locale,
    Object.freeze({ ...LEGACY_LINT_TRANSLATIONS[locale], ...LEGACY_LINT_QUALITY_OVERRIDES[locale] })
  ]))
});

export function normalizeLegacyLintLocale(value) {
  const compact = String(value ?? "").replace(/[-_]/g, "").toLowerCase();
  return LEGACY_LINT_LOCALES.find((locale) => locale.toLowerCase() === compact) ?? LEGACY_LINT_DEFAULT_LOCALE;
}

export function legacyMessage(key, params = {}) {
  const descriptor = { legacyKey: String(key), params: Object.freeze({ ...params }) };
  Object.defineProperty(descriptor, "toString", {
    enumerable: false,
    value: () => resolveLegacyMessage(descriptor, LEGACY_LINT_DEFAULT_LOCALE)
  });
  return Object.freeze(descriptor);
}

export function legacyTerm(key) {
  const descriptor = { legacyTermKey: String(key) };
  Object.defineProperty(descriptor, "toString", {
    enumerable: false,
    value: () => `term:${descriptor.legacyTermKey}`
  });
  return Object.freeze(descriptor);
}

export function resolveLegacyMessage(message, locale = LEGACY_LINT_DEFAULT_LOCALE, { escape = false } = {}) {
  const key = typeof message === "string" ? message : message?.legacyKey;
  const params = typeof message === "object" ? message?.params ?? {} : {};
  const catalog = legacyLintCatalogs[normalizeLegacyLintLocale(locale)];
  const template = catalog[key] ?? legacyLintCatalogs.enUS[key] ?? String(key ?? "");
  return template.replace(/\{([A-Za-z][A-Za-z0-9_]*)\}/g, (_, name) => {
    const value = resolveLegacyParameter(params[name], locale);
    return escape ? escapeHtml(value) : value;
  });
}

export function legacyMessageText(key, params = {}, locale = LEGACY_LINT_DEFAULT_LOCALE) {
  return resolveLegacyMessage(legacyMessage(key, params), locale);
}

export function legacyRuleMetadata(id, locale = LEGACY_LINT_DEFAULT_LOCALE) {
  const normalized = normalizeLegacyLintLocale(locale);
  const english = legacyLintEnglishRuleMetadata[id] ?? [id, ""];
  if (normalized === "enUS") return { label: english[0], note: english[1] };
  const translated = LEGACY_LINT_RULE_METADATA_QUALITY_OVERRIDES[normalized]?.[id]
    ?? LEGACY_LINT_RULE_METADATA_TRANSLATIONS[normalized]?.[id];
  return { label: translated?.[0] ?? english[0], note: translated?.[1] ?? english[1] };
}

