export function validateLegacyLintCatalogs() {
  const keys = Object.keys(EN_MESSAGES);
  for (const locale of LEGACY_LINT_LOCALES) {
    for (const key of keys) {
      if (!legacyLintCatalogs[locale][key]) throw new Error(`Missing legacy lint translation: ${locale}:${key}`);
    }
  }
  return { keys: keys.length, locales: LEGACY_LINT_LOCALES.length };
}

export const legacyLintCatalogValidation = validateLegacyLintCatalogs();

function escapeHtml(value) {
  return String(value).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

function resolveLegacyParameter(value, locale) {
  if (value?.legacyTermKey) {
    const normalized = normalizeLegacyLintLocale(locale);
    return LEGACY_LINT_TERMS[normalized]?.[value.legacyTermKey]
      ?? LEGACY_LINT_LEGEND_TERMS[normalized]?.[value.legacyTermKey]
      ?? LEGACY_LINT_TERMS.enUS[value.legacyTermKey]
      ?? LEGACY_LINT_LEGEND_TERMS.enUS[value.legacyTermKey]
      ?? value.legacyTermKey;
  }
  return String(value ?? "");
}
